func solve(words: Array<String>) -> Array<Int64> {
    let n = words.count
    if n == 1 {
        return [0]
    }
    let charWords = words.map { Array($0) }
    var consecutive = [Int](repeating: 0, count: n - 1)
    for i in 0..<n - 1 {
        let a = charWords[i]
        let b = charWords[i + 1]
        var j = 0
        while j < a.count && j < b.count && a[j] == b[j] {
            j += 1
        }
        consecutive[i] = j
    }

    var leftMax = [Int](repeating: 0, count: n - 1)
    leftMax[0] = consecutive[0]
    if n - 1 > 1 {
        for i in 1..<n - 1 {
            leftMax[i] = max(leftMax[i - 1], consecutive[i])
        }
    }

    var rightMax = [Int](repeating: 0, count: n - 1)
    rightMax[n - 2] = consecutive[n - 2]
    if n - 1 > 1 {
        for i in stride(from: n - 3, through: 0, by: -1) {
            rightMax[i] = max(consecutive[i], rightMax[i + 1])
        }
    }

    var ans = [Int64](repeating: 0, count: n)
    for i in 0..<n {
        var candidate: Int = 0
        if i >= 2 {
            candidate = max(candidate, leftMax[i - 2])
        }
        if i <= n - 3 {
            candidate = max(candidate, rightMax[i + 1])
        }
        if i >= 1 && i <= n - 2 {
            let a = charWords[i - 1]
            let b = charWords[i + 1]
            var j = 0
            while j < a.count && j < b.count && a[j] == b[j] {
                j += 1
            }
            candidate = max(candidate, j)
        }
        ans[i] = Int64(candidate)
    }
    return ans
}
```

