func common_prefix(a: String, b: String) -> Int {
    int n = min(a.length(), b.length())
    int i = 0
    while i < n {
        if a[i] != b[i] {
            break
        }
        i += 1
    }
    return i
}

func solve(words: Array<String>): Array<Int64> {
    let n = words.length()
    if n == 1 {
        return [0]
    }
    let m = n - 1
    var cp = Array<Int>()
    for i in 0..m {
        cp.push(common_prefix(words[i], words[i+1]))
    }

    var left_max = Array<Int>(size: m, init: 0)
    var right_max = Array<Int>(size: m, init: 0)

    if m > 0 {
        left_max[0] = cp[0]
        for i in 1..m {
            left_max[i] = max(left_max[i-1], cp[i])
        }

        right_max[m-1] = cp[m-1]
        for i in (0..(m-2)).descending() {
            right_max[i] = max(right_max[i+1], cp[i])
        }
    }

    var ans = Array<Int64>(size: n, init: 0)

    for i in 0..n {
        int cand = 0
        if i >= 2 {
            cand = max(cand, left_max[i-2])
        }
        if i >= 1 && i < n-1 {
            let mid_val = common_prefix(words[i-1], words[i+1])
            cand = max(cand, mid_val)
        }
        if i <= n-3 {
            cand = max(cand, right_max[i+1])
        }
        ans[i] = Int64(cand)
    }

    return ans
}
