func solve(words: Array<String>): Array<Int64> {
    n = words.length()
    // Handle empty input
    if n == 0 {
        return []
    }
    // Initialize common array for adjacent pairs
    common = array(n-1, 0: Int64)
    if n >= 2 {
        for i in range(0, n-1) {
            s = words[i]
            t = words[i+1]
            len_s = s.length()
            len_t = t.length()
            min_len = min(len_s, len_t)
            j = 0
            while (j < min_len) {
                if (s[j] != t[j]) {
                    break
                }
                j = j + 1
            }
            common[i] = j
        }
    }
    // Precompute prefix_max: max from 0 to current
    prefix_max = array(n, 0: Int64)
    if n > 1 {
        for i in range(1, n) {
            current_common = if i-1 < n-1 then common[i-1] else 0
            prefix_max[i] = if prefix_max[i-1] > current_common then prefix_max[i-1] else current_common
        }
    }
    // Precompute suffix_max: max from current to end
    suffix_max = array(n, 0: Int64)
    if n > 1 {
        suffix_max[n-2] = common[n-2]
        for i from n-3 down to 0 {
            suffix_max[i] = if common[i] > suffix_max[i+1] then common[i] else suffix_max[i+1]
        }
    }
    // Initialize answer array
    ans = array(n, 0: Int64)
    // Process each removal index
    for i in range(0, n) {
        candidate_left = 0: Int64
        candidate_mid = 0: Int64
        candidate_right = 0: Int64
        // Left segment: indices [0, i-2]
        if i >= 2 {
            candidate_left = prefix_max[i-1]
        }
        // New pair: indices (i-1, i+1) if applicable
        if i >= 1 && i <= n-2 {
            s1 = words[i-1]
            s2 = words[i+1]
            len1 = s1.length()
            len2 = s2.length()
            min_len = if len1 < len2 then len1 else len2
            j = 0
            while (j < min_len) {
                if (s1[j] != s2[j]) {
                    break
                }
                j = j + 1
            }
            candidate_mid = j
        }
        // Right segment: indices [i+1, n-2]
        if i <= n-3 {
            candidate_right = suffix_max[i+1]
        }
        // Compute maximum of three candidates
        max_val = candidate_left
        if candidate_mid > max_val {
            max_val = candidate_mid
        }
        if candidate_right > max_val {
            max_val = candidate_right
        }
        ans[i] = max_val
    }
    return ans
}
```

